FROM cve_cwe 
WHERE cwe_id = 'CWE-1059';

SELECT COUNT(*) AS cve_count
FROM cve AS c
WHERE c.published LIKE '2022%' AND c.cvss_v3_score > 9.0;

SELECT COUNT(*) AS critical_vulnerabilities_count
FROM cve AS c
WHERE c.cvss_v3_severity = 'CRITICAL' AND c.published LIKE '2022-%';

